from jinja2 import Environment
from jinja2.ext import i18n

env = Environment(extensions=[i18n])

translations = {
    ('mydomain', 'Hello'): 'Bonjour',
    ('mydomain', 'default'): ('%(num)s cat', '%(num)s cats'),
}

def dgettext(domain, message):
    return translations.get((domain, message), message)

def dngettext(domain, singular, plural, n):
    if n == 1:
        return translations.get((domain, singular), singular)
    return translations.get((domain, singular), (None, plural))[1] if (domain, singular) in translations else plural

env.install_gettext_callables(
    gettext=lambda s: s,
    ngettext=lambda s, p, n: s if n == 1 else p,
    newstyle=False,
)
env.globals['dgettext'] = dgettext
env.globals['dngettext'] = dngettext

tmpl = env.from_string('{% trans domain=\"mydomain\" %}Hello{% endtrans %}')
print(tmpl.render())

tmpl2 = env.from_string('{% trans domain=\"mydomain\", count=3 %}{{ count }} item{% pluralize %}{{ count }} items{% endtrans %}')
print(tmpl2.render())

tmpl3 = env.from_string('{% trans %}Hello{% endtrans %}')
print(tmpl3.render())
"
